{"path":"packages/runner/src/runner.ts","content":"import { simpleGit, SimpleGit } from 'simple-git';
import { Run, RunLog, RunStatus } from '@repopilot/shared';
import { EventEmitter } from 'events';
import fs from 'fs/promises';
import path from 'path';

export interface RunnerCallbacks {
  onLog: (log: Omit<RunLog, 'id' | 'createdAt'>) => Promise<void>;
  onStatusChange: (status: RunStatus, errorMessage?: string) => Promise<void>;
}

export class MockRunner extends EventEmitter {
  private git: SimpleGit | null = null;

  async execute(run: Run, callbacks: RunnerCallbacks): Promise<void> {
    try {
      await callbacks.onStatusChange('running');
      await callbacks.onLog({ runId: run.id, level: 'info', message: 'Agent started' });

      this.git = simpleGit(run.workspacePath);

      // Create or update AGENT_RUN.md
      const agentRunPath = path.join(run.workspacePath, 'AGENT_RUN.md');
      let content = '';
      try {
        content = await fs.readFile(agentRunPath, 'utf-8');
      } catch {
        // File doesn't exist yet
      }

      const timestamp = new Date().toISOString();
      const newEntry = `\n## Run ${run.id} - ${timestamp}\n\n**Agent:** ${run.agent}\n**Prompt:** ${run.prompt}\n\n**Generated Note:**\nThis change was generated by the mock agent in response to the prompt: "${run.prompt}"\n`;

      content += newEntry;
      await fs.writeFile(agentRunPath, content);
      await callbacks.onLog({ runId: run.id, level: 'info', message: `File changed: AGENT_RUN.md` });

      // Stage and commit
      await this.git.add('AGENT_RUN.md');
      await this.git.commit(`Agent run ${run.id}: ${run.prompt}`, undefined, {
        '--author': 'RepoPilot Agent <agent@repopilot.local>',
      });
      await callbacks.onLog({ runId: run.id, level: 'info', message: 'Commit created' });

      await callbacks.onStatusChange('completed');
      await callbacks.onLog({ runId: run.id, level: 'info', message: 'Run completed' });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      await callbacks.onLog({ runId: run.id, level: 'error', message: `Error: ${message}` });
      await callbacks.onStatusChange('failed', message);
      throw error;
    }
  }
}
"}

{"path":"apps/api/src/db/schema.ts","content":"import { sqliteTable, integer, text } from 'drizzle-orm/sqlite-core';

export const runs = sqliteTable('runs', {
  id: integer('id', { mode: 'number' }).primaryKey({ autoIncrement: true }),
  repoUrl: text('repo_url').notNull(),
  baseBranch: text('base_branch').notNull(),
  branchName: text('branch_name').notNull(),
  prompt: text('prompt').notNull(),
  agent: text('agent').notNull(),
  status: text('status', { enum: ['queued', 'running', 'completed', 'failed', 'rejected', 'approved'] }).notNull(),
  workspacePath: text('workspace_path').notNull(),
  errorMessage: text('error_message'),
  approvedAt: text('approved_at'),
  rejectedAt: text('rejected_at'),
  rejectionFeedback: text('rejection_feedback'),
  createdAt: text('created_at').notNull(),
  updatedAt: text('updated_at').notNull(),
});

export const runLogs = sqliteTable('run_logs', {
  id: integer('id', { mode: 'number' }).primaryKey({ autoIncrement: true }),
  runId: integer('run_id', { mode: 'number' }).notNull(),
  level: text('level', { enum: ['info', 'warn', 'error'] }).notNull(),
  message: text('message').notNull(),
  createdAt: text('created_at').notNull(),
});
"}

