{"path":"apps/api/src/services/runService.ts","content":"import { eq } from 'drizzle-orm';
import { db } from '../db/index.js';
import { runs, runLogs } from '../db/schema.js';
import { Run, RunStatus, RunLog, CreateRunRequest } from '@repopilot/shared';
import { MockRunner } from '@repopilot/runner';
import { simpleGit } from 'simple-git';
import path from 'path';
import fs from 'fs/promises';
import { EventEmitter } from 'events';

const logEmitter = new EventEmitter();

export async function createRun(data: CreateRunRequest): Promise<Run> {
  const timestamp = new Date().toISOString();
  const workspaceBase = process.env.WORKSPACE_BASE || './workspaces';
  await fs.mkdir(workspaceBase, { recursive: true });

  const result = db.insert(runs).values({
    repoUrl: data.repoUrl,
    baseBranch: data.baseBranch,
    branchName: '', // Will be updated after we have the ID
    prompt: data.prompt,
    agent: data.agent,
    status: 'queued',
    workspacePath: '', // Will be updated after we have the ID
    createdAt: timestamp,
    updatedAt: timestamp,
  }).returning().get();

  const workspacePath = path.resolve(workspaceBase, `run-${result.id}`);
  const branchName = `agent/run-${result.id}`;

  db.update(runs)
    .set({ workspacePath, branchName })
    .where(eq(runs.id, result.id))
    .run();

  const run: Run = {
    ...result,
    workspacePath,
    branchName,
    errorMessage: null,
    approvedAt: null,
    rejectedAt: null,
    rejectionFeedback: null,
  };

  // Start background job
  processRun(run).catch(console.error);

  return run;
}

async function processRun(run: Run): Promise<void> {
  const runner = new MockRunner();

  const addLog = async (level: RunLog['level'], message: string) => {
    const timestamp = new Date().toISOString();
    const log = db.insert(runLogs).values({
      runId: run.id,
      level,
      message,
      createdAt: timestamp,
    }).returning().get();
    logEmitter.emit(`log:${run.id}`, log);
  };

  try {
    await addLog('info', `Cloning repo: ${run.repoUrl}`);
    const git = simpleGit();
    await git.clone(run.repoUrl, run.workspacePath, ['--branch', run.baseBranch, '--single-branch']);
    await addLog('info', 'Repo cloned');

    const repoGit = simpleGit(run.workspacePath);
    await repoGit.checkoutLocalBranch(run.branchName);
    await addLog('info', `Branch created: ${run.branchName}`);

    await runner.execute(run, {
      onLog: async (log) => addLog(log.level, log.message),
      onStatusChange: async (status, errorMessage) => {
        db.update(runs)
          .set({ status, errorMessage: errorMessage || null, updatedAt: new Date().toISOString() })
          .where(eq(runs.id, run.id))
          .run();
      },
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    await addLog('error', `Runner crashed: ${message}`);
    db.update(runs)
      .set({ status: 'failed', errorMessage: message, updatedAt: new Date().toISOString() })
      .where(eq(runs.id, run.id))
      .run();
  }
}

export function getRuns(): Run[] {
  return db.select().from(runs).all().map(mapRun);
}

export function getRunById(id: number): Run | undefined {
  const row = db.select().from(runs).where(eq(runs.id, id)).get();
  return row ? mapRun(row) : undefined;
}

export function getRunLogs(runId: number): RunLog[] {
  return db.select().from(runLogs).where(eq(runLogs.runId, runId)).all();
}

export function subscribeToLogs(runId: number, callback: (log: RunLog) => void): () => void {
  const handler = (log: RunLog) => callback(log);
  logEmitter.on(`log:${runId}`, handler);
  return () => logEmitter.off(`log:${runId}`, handler);
}

export async function getDiff(runId: number): Promise<{ files: Array<{ path: string; additions: number; deletions: number; patch: string }> } | { error: string }> {
  const run = getRunById(runId);
  if (!run) return { error: 'Run not found' };

  try {
    const git = simpleGit(run.workspacePath);
    const diff = await git.diff([`${run.baseBranch}...${run.branchName}`]);
    return { files: parseDiff(diff) };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { error: message };
  }
}

function parseDiff(diff: string): Array<{ path: string; additions: number; deletions: number; patch: string }> {
  const files: Array<{ path: string; additions: number; deletions: number; patch: string }> = [];
  const lines = diff.split('\n');
  let currentFile: { path: string; additions: number; deletions: number; patch: string } | null = null;

  for (const line of lines) {
    if (line.startsWith('diff --git')) {
      if (currentFile) files.push(currentFile);
      const match = line.match(/diff --git a\/(.+?) b\/(.+)/);
      currentFile = { path: match?.[2] || '', additions: 0, deletions: 0, patch: line + '\n' };
    } else if (currentFile) {
      currentFile.patch += line + '\n';
      if (line.startsWith('+') && !line.startsWith('+++')) currentFile.additions++;
      if (line.startsWith('-') && !line.startsWith('---')) currentFile.deletions++;
    }
  }

  if (currentFile) files.push(currentFile);
  return files;
}

export function approveRun(id: number): { success: boolean; error?: string } {
  const run = getRunById(id);
  if (!run) return { success: false, error: 'Run not found' };
  if (run.status === 'failed') return { success: false, error: 'Cannot approve a failed run' };
  if (run.status === 'rejected') return { success: false, error: 'Cannot approve a rejected run' };
  if (run.status === 'approved') return { success: false, error: 'Run is already approved' };

  db.update(runs)
    .set({ status: 'approved', approvedAt: new Date().toISOString(), updatedAt: new Date().toISOString() })
    .where(eq(runs.id, id))
    .run();

  return { success: true };
}

export function rejectRun(id: number, feedback: string): { success: boolean; error?: string } {
  const run = getRunById(id);
  if (!run) return { success: false, error: 'Run not found' };
  if (run.status === 'approved') return { success: false, error: 'Cannot reject an approved run' };
  if (run.status === 'rejected') return { success: false, error: 'Run is already rejected' };

  db.update(runs)
    .set({
      status: 'rejected',
      rejectionFeedback: feedback,
      rejectedAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    })
    .where(eq(runs.id, id))
    .run();

  return { success: true };
}

function mapRun(row: typeof runs.$inferSelect): Run {
  return {
    id: row.id,
    repoUrl: row.repoUrl,
    baseBranch: row.baseBranch,
    branchName: row.branchName,
    prompt: row.prompt,
    agent: row.agent,
    status: row.status as RunStatus,
    workspacePath: row.workspacePath,
    errorMessage: row.errorMessage,
    approvedAt: row.approvedAt,
    rejectedAt: row.rejectedAt,
    rejectionFeedback: row.rejectionFeedback,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
  };
}
"}

