import { createRunSchema, rejectRunSchema } from '@repopilot/shared';
import {
  createRun,
  getRuns,
  getRunById,
  getRunLogs,
  subscribeToLogs,
  getDiff,
  approveRun,
  rejectRun,
} from '../services/runService.js';

export async function runRoutes(fastify: FastifyInstance) {
  fastify.post('/', async (request, reply) => {
    const parse = createRunSchema.safeParse(request.body);
    if (!parse.success) {
      return reply.status(400).send({ error: parse.error.errors.map((e) => e.message).join(', ') });
    }
    const run = await createRun(parse.data);
    return reply.status(201).send(run);
  });

  fastify.get('/', async () => {
    return getRuns();
  });

  fastify.get('/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const run = getRunById(Number(id));
    if (!run) return reply.status(404).send({ error: 'Run not found' });
    return run;
  });

  fastify.get('/:id/logs', async (request, reply) => {
    const { id } = request.params as { id: string };
    const runId = Number(id);
    const run = getRunById(runId);
    if (!run) return reply.status(404).send({ error: 'Run not found' });

    const accept = request.headers.accept || '';
    if (accept.includes('text/event-stream')) {
      reply.raw.writeHead(200, {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        Connection: 'keep-alive',
      });

      const logs = getRunLogs(runId);
      for (const log of logs) {
        reply.raw.write(`data: ${JSON.stringify(log)}\n\n`);
      }

      const unsubscribe = subscribeToLogs(runId, (log) => {
        reply.raw.write(`data: ${JSON.stringify(log)}\n\n`);
      });

      request.raw.on('close', () => {
        unsubscribe();
      });

      return reply;
    }

    return getRunLogs(runId);
  });

  fastify.get('/:id/diff', async (request, reply) => {
    const { id } = request.params as { id: string };
    const runId = Number(id);
    const run = getRunById(runId);
    if (!run) return reply.status(404).send({ error: 'Run not found' });

    const result = await getDiff(runId);
    if ('error' in result) {
      return reply.status(400).send({ error: result.error });
    }
    return result;
  });

  fastify.post('/:id/approve', async (request, reply) => {
    const { id } = request.params as { id: string };
    const result = approveRun(Number(id));
    if (!result.success) return reply.status(400).send({ error: result.error });
    return { success: true };
  });

  fastify.post('/:id/reject', async (request, reply) => {
    const { id } = request.params as { id: string };
    const parse = rejectRunSchema.safeParse(request.body);
    if (!parse.success) {
      return reply.status(400).send({ error: parse.error.errors.map((e) => e.message).join(', ') });
    }
    const result = rejectRun(Number(id), parse.data.feedback);
    if (!result.success) return reply.status(400).send({ error: result.error });
    return { success: true };
  });
}
"}

